// Whitelist of trusted RSS sources
const sources = [
  { name: 'PIB India',       url: 'https://www.pib.gov.in/RssMain.aspx?ModId=6&Lang=1&Regid=3', category: 'india' },
  { name: 'India.gov.in',    url: 'https://www.india.gov.in/news_feeds/feed/rss', category: 'india' },
  { name: 'Google Blog',     url: 'https://blog.google/rss/', category: 'tech' },
  { name: 'OpenAI News',     url: 'https://openai.com/news/rss.xml', category: 'tech' },
  { name: 'Microsoft News',  url: 'https://news.microsoft.com/feed/', category: 'tech' },
  { name: 'AWS Blog',        url: 'https://aws.amazon.com/blogs/aws/feed/', category: 'tech' },
  { name: 'Cloudflare Blog', url: 'https://blog.cloudflare.com/rss/', category: 'tech' },
  { name: 'PR Newswire',     url: 'https://www.prnewswire.com/rss/news-releases-list.rss', category: 'business' },
  { name: 'GlobeNewswire',   url: 'https://www.globenewswire.com/RssFeed/subjects/news', category: 'business' }
];

return sources.map(s => ({ json: s }));

// Parse XML and extract last 3 items per source
const Parser = require('rss-parser');
const parser = new Parser({ timeout: 15000 });

const sourceMeta = $('Source Whitelist').item.json;
const rawXml = $input.item.json.data || $input.item.json.body || '';

if (!rawXml || typeof rawXml !== 'string') {
  return [];
}

try {
  const feed = await parser.parseString(rawXml);
  const items = (feed.items || []).slice(0, 3); // Top 3 latest per source
  return items.map(item => ({
    json: {
      source_name: sourceMeta.name,
      category_slug: sourceMeta.category,
      source_url: item.link,
      source_published_at: item.isoDate || item.pubDate,
      title: item.title,
      raw_content: (item.contentSnippet || item.content || item.summary || item.title || '').slice(0, 4000)
    }
  }));
} catch (e) {
  return [{ json: { error: e.message, source: sourceMeta.name } }];
}

// Aggregate results for the daily report
const items = $input.all();
const summary = {
  total: items.length,
  published: items.filter(i => i.json?.status === 'published').length,
  duplicates: items.filter(i => i.json?.status === 'duplicate').length,
  failed: items.filter(i => i.json?.error).length,
  details: items.map(i => ({
    slug: i.json?.slug,
    status: i.json?.status,
    error: i.json?.error
  }))
};
return [{ json: summary }];
